export type SlotStatus = "stable" | "incomplet" | "sous_tension" | "surcharge";
export type SlotType = "wake" | "meal" | "water" | "activity" | "day_close";

export type CoachNote = {
  id: string;
  coach_id: string;
  client_id: string;
  scope: "slot" | "day" | "week";
  scope_ref: string;
  content: string;
  visibility: "client" | "coach";
  annotation_type: "observation" | "question" | "recommandation";
  created_at: string;
};

export type AgendaSlot = {
  slot_id: string;
  slot_type: SlotType;
  period: "day";
  date: string; // YYYY-MM-DD
  status: SlotStatus;
  auto_summary: string;
  coach_notes?: CoachNote[]; // Array of notes
};

export type Recommendation = {
  id: string;
  scope: "day" | "week";
  type: "observation" | "hypothesis" | "proposal";
  text: string;
  related_slot_id?: string;
};

export type ClientAgendaUIProps = {
  date: string; // YYYY-MM-DD
  agenda_slots: AgendaSlot[];
  recommendations: Recommendation[];
};

