import { AgendaSlot, ClientAgendaUIProps, SlotStatus, SlotType } from "@/lib/types";

// Raw Event Interface matching Supabase 'events'
export interface RawEvent {
    id: string;
    user_id: string;
    event_type: string;
    payload: any;
    created_at: string; // ISO string
}

export type EngineContext = {
    timezone: string;
    referenceDate: string; // YYYY-MM-DD
    annotations?: any[]; // CoachNote[]
};

// ------------------------------------------------------------------
// PURE FUNCTION: buildAgenda
// ------------------------------------------------------------------
export function buildAgenda(events: RawEvent[], context: EngineContext): ClientAgendaUIProps {
    // 1. Filter events for the reference date (simple string match on ISO for V0 POC, or better date-fns)
    // For V0, we assume 'events' passed in are already roughly filtered or we filter here.
    // We'll trust the caller to pass relevant events.

    const dayEvents = events; // In a real engine, we'd filter by day.

    // 2. Initialize Slots (Empty Skeleton)
    const slots: AgendaSlot[] = [
        createSlot("wake", "wake", "incomplet", context.referenceDate),
        createSlot("meal", "meal", "incomplet", context.referenceDate),
        createSlot("water", "water", "incomplet", context.referenceDate),
        createSlot("activity", "activity", "incomplet", context.referenceDate),
        createSlot("day_close", "day_close", "incomplet", context.referenceDate),
    ];

    // 3. Map Events to Slots & Calculate Status
    // Rules V0:
    // wake: incomplet if no event.
    // meal: incomplet if < 2 meals.
    // water: incomplet if < threshold (e.g. 1500ml).
    // activity: stable (default).
    // day_close: incomplet if absent.

    // --- WAKE ---
    const wakeEvents = dayEvents.filter(e => e.event_type.includes("wake"));
    const wakeSlot = slots.find(s => s.slot_type === "wake")!;
    if (wakeEvents.length === 0) {
        wakeSlot.status = "incomplet";
        wakeSlot.auto_summary = "En attente de check-in";
    } else {
        wakeSlot.status = "stable";
        wakeSlot.auto_summary = `Check-in à ${formatTime(wakeEvents[0].created_at)}`;
    }

    // --- MEAL ---
    const mealEvents = dayEvents.filter(e => e.event_type.includes("meal"));
    const mealSlot = slots.find(s => s.slot_type === "meal")!;
    if (mealEvents.length === 0) {
        mealSlot.status = "incomplet";
        mealSlot.auto_summary = "Aucun repas enregistré";
    } else if (mealEvents.length < 2) {
        mealSlot.status = "incomplet"; // Rule: < 2 meals
        mealSlot.auto_summary = `1 repas enregistré`;
    } else {
        mealSlot.status = "stable";
        mealSlot.auto_summary = `${mealEvents.length} repas enregistrés`;
    }

    // --- WATER ---
    const waterEvents = dayEvents.filter(e => e.event_type.includes("water"));
    const waterSlot = slots.find(s => s.slot_type === "water")!;
    // Calculate total ML
    let totalWater = 0;
    waterEvents.forEach(e => {
        // payload might have 'water_ml' or 'volume'
        // V0 QuickInputSheet sends 'water_ml'
        totalWater += Number(e.payload?.water_ml || 0);
    });

    if (totalWater < 1500) {
        waterSlot.status = "incomplet";
        waterSlot.auto_summary = `${totalWater}ml / 1500ml`;
    } else {
        waterSlot.status = "stable";
        waterSlot.auto_summary = `Objectif atteint (${totalWater}ml)`;
    }

    // --- ACTIVITY ---
    const activityEvents = dayEvents.filter(e => e.event_type.includes("activity"));
    const actSlot = slots.find(s => s.slot_type === "activity")!;
    if (activityEvents.length > 0) {
        actSlot.auto_summary = `${activityEvents.length} activité(s)`;
        actSlot.status = "stable"; // Assuming stable if done
    } else {
        actSlot.auto_summary = "Repos";
        actSlot.status = "stable"; // Default stable for activity if empty? or incomplet? Rule 5.3 says "sous_tension : activity + stress". "stable : sinon". 
        // So logic: always stable unless checks fail.
    }

    // --- DAY CLOSE ---
    const closeEvents = dayEvents.filter(e => e.event_type.includes("day_close"));
    const closeSlot = slots.find(s => s.slot_type === "day_close")!;
    if (closeEvents.length === 0) {
        closeSlot.status = "incomplet";
        closeSlot.auto_summary = "Journée en cours";
    } else {
        closeSlot.status = "stable";
        closeSlot.auto_summary = "Clôturée";
    }

    // --- ATTACH ANNOTATIONS ---
    // Simple mapping based on slot_id (which is slot_type in V0 single-day context? 
    // No, slot_id in createSlot is "wake", "meal" etc.
    // Annotation table has 'slot_id' + 'date'.
    // Context has 'annotations'.
    const notes = context.annotations || [];
    slots.forEach(slot => {
        // Filter by scope=slot and scope_ref=slot_id (legacy logic was slot_id=slot_id, now scope_ref)
        const relevantNotes = notes.filter(n =>
            n.scope === 'slot' &&
            n.scope_ref === slot.slot_id &&
            // In V0, we fetch annotations for the specific DAY in the API.
            // If the API filters correctly by Client+Date, do we need to check date here?
            // The table doesn't have a 'date' column anymore in strict schema? 
            // Wait, I removed 'date' column in the strict schema 'create table coach_annotations'.
            // It has 'scope_ref'. For slot scope, scope_ref is slot_id.
            // But how do we distinguish dates? 
            // Ah, the strict schema I applied: scope_ref text not null.
            // A slot_id like "wake" repeats every day.
            // The user strict requirement "scope_ref text -- slot_id | date | week_id" implies ID reference.
            // But if there is no date column, unique identification is impossible for "wake".
            // Unless "scope_ref" is a composite like "2024-01-01_wake"?
            // OR I made a mistake removing the date column without adding it to scope_ref.
            // V0 features lock says "clic slot -> lecture + annotation".
            // I must re-add 'date' column or 'created_at' usage? No, 'date' of the event.
            // I will assume for V0 execution to add 'date' back or encode it.
            // Let's check strict requirements: "scope text, scope_ref text".
            // I will use scope_ref = "YYYY-MM-DD_slotID" for slots.
            n.scope_ref === `${context.referenceDate}_${slot.slot_id}`
        );
        if (relevantNotes.length > 0) {
            slot.coach_notes = relevantNotes;
        }
    });

    // Return strict ClientAgendaUIProps
    return {
        date: context.referenceDate,
        agenda_slots: slots,
        recommendations: [] // V0: empty for now
    };
}

// Helpers
function createSlot(id: string, type: SlotType, status: SlotStatus, date: string): AgendaSlot {
    return {
        slot_id: id,
        slot_type: type,
        period: "day",
        date: date,
        status: status, // Default init
        auto_summary: "",
        coach_notes: []
    };
}

function formatTime(iso: string) {
    try {
        return new Date(iso).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
    } catch { return "--:--"; }
}

import type { ClientAgendaUIProps } from "./types";

export const mockAgenda: ClientAgendaUIProps = {
  date: "2026-02-10",
  agenda_slots: [
    {
      slot_id: "slot_wake",
      slot_type: "wake",
      period: "day",
      date: "2023-10-27",
      status: "stable",
      auto_summary: "Sommeil 7h00 • Qualité 4/5 • Énergie 3/5 • Humeur 4/5",
      coach_notes: [],
    },
    {
      slot_id: "slot_meal",
      slot_type: "meal",
      period: "day",
      date: "2026-02-10",
      status: "sous_tension",
      auto_summary: "Repas irréguliers • Faim élevée avant déjeuner • Dîner tardif",
    },
    {
      slot_id: "slot_water",
      slot_type: "water",
      period: "day",
      date: "2026-02-10",
      status: "incomplet",
      auto_summary: "Hydratation estimée : 900 ml (objectif 2000 ml)",
    },
    {
      slot_id: "slot_activity",
      slot_type: "activity",
      period: "day",
      date: "2026-02-10",
      status: "stable",
      auto_summary: "Marche 35 min • Intensité 2/5 • Ressenti 4/5",
    },
    {
      slot_id: "slot_close",
      slot_type: "day_close",
      period: "day",
      date: "2026-02-10",
      status: "incomplet",
      auto_summary: "Fin de journée non remplie",
    },
  ],
  recommendations: [
    {
      id: "rec_1",
      scope: "day",
      type: "proposal",
      text: "Tester un ancrage repas (déjeuner avant 13h) pour stabiliser la faim.",
      related_slot_id: "slot_meal",
    },
  ],
};

