"use client";

import * as React from "react";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { TooltipProvider } from "@/components/ui/tooltip";
import { AgendaSlotCard } from "@/components/agenda/agenda-slot-card";
import { ActionBar } from "@/components/agenda/action-bar";
import { QuickInputSheet } from "@/components/agenda/quick-input-sheet";
import { DevAuth } from "@/components/dev-auth";
import { AgendaSlot, SlotType, ClientAgendaUIProps } from "@/lib/types";
import { NotificationsList } from "@/components/notifications-list";
import { Settings } from "lucide-react";
import Link from "next/link";

function computeAdherencePercent(slots: AgendaSlot[]): number {
  const score = slots.reduce((acc, s) => {
    if (s.status === "stable") return acc + 1;
    if (s.status === "sous_tension") return acc + 0.5;
    return acc;
  }, 0);
  const pct = Math.round((score / Math.max(1, slots.length)) * 100);
  return Math.max(0, Math.min(100, pct));
}

export default function AgendaPage() {
  const [, setActiveSlot] = React.useState<AgendaSlot | null>(null);
  const [sheetOpen, setSheetOpen] = React.useState(false);
  const [sheetSlotType, setSheetSlotType] = React.useState<SlotType | null>(null);

  // State for Agenda Data
  const [agenda, setAgenda] = React.useState<ClientAgendaUIProps | null>(null);
  const [loading, setLoading] = React.useState(true);

  // Fetch Agenda
  const fetchAgenda = React.useCallback(async () => {
    try {
      // In V0, we assume the user is logged in (handled by middleware or Client check).
      // We fetch the agenda for "today".
      const res = await fetch("/api/agenda");
      if (res.ok) {
        const data = await res.json();
        setAgenda(data);
      } else {
        console.error("Failed to fetch agenda status:", res.status);
        if (res.status === 401) {
          setAgenda(null); // Trigger login msg
        }
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, []);

  React.useEffect(() => {
    fetchAgenda();
  }, [fetchAgenda]);

  const adherence = agenda ? computeAdherencePercent(agenda.agenda_slots) : 0;

  function openSlot(slot: AgendaSlot) {
    setActiveSlot(slot);
    if (slot.status === "incomplet") {
      setSheetSlotType(slot.slot_type);
      setSheetOpen(true);
    } else {
      setSheetSlotType(slot.slot_type);
      setSheetOpen(true);
    }
  }

  function quickOpen(slotType: SlotType) {
    setActiveSlot(null);
    setSheetSlotType(slotType);
    setSheetOpen(true);
  }

  function submitMock(payload: Record<string, unknown>) {
    console.log("[SUBMIT]", payload);
    setTimeout(() => {
      fetchAgenda();
    }, 500);
  }

  if (loading) {
    return <div className="flex h-dvh items-center justify-center text-sm text-muted-foreground">Chargement de l'agenda...</div>;
  }

  if (!agenda) {
    return (
      <div className="flex flex-col h-dvh items-center justify-center gap-4 p-4 text-center">
        <div className="text-sm text-muted-foreground">Session expirée ou non connectée.</div>
        <DevAuth />
      </div>
    );
  }

  return (
    <TooltipProvider>
      <div className="mx-auto flex min-h-dvh max-w-xl flex-col">
        {/* Header */}
        <div className="px-4 pt-5">
          <div className="flex items-start justify-between gap-3">
            <div>
              <div className="text-xl font-semibold tracking-tight">Agenda</div>
              <div className="mt-1 text-sm text-muted-foreground">{agenda.date}</div>
            </div>
            <div className="flex items-center gap-2">
              <Link href="/settings">
                <div className="p-2 rounded-full hover:bg-muted transition-colors">
                  <Settings className="h-5 w-5 text-muted-foreground" />
                </div>
              </Link>
              <Badge variant="outline">{adherence}%</Badge>
            </div>
          </div>

          <div className="mt-4">
            <Progress value={adherence} />
            <div className="mt-2 text-xs text-muted-foreground">
              Indicateur v0 — SmartAgendaEngine Active.
            </div>
          </div>
        </div>

        <Separator className="my-4" />

        {/* Notifications */}
        <div className="px-4">
          <NotificationsList />
        </div>

        {/* Agenda day */}
        <ScrollArea className="flex-1 px-4">
          <div className="space-y-3 pb-24">
            {agenda.agenda_slots.map((slot) => (
              <AgendaSlotCard key={slot.slot_id} slot={slot} onOpen={openSlot} />
            ))}
          </div>
        </ScrollArea>

        {/* Bottom action bar */}
        <ActionBar onQuickOpen={quickOpen} />

        {/* Quick input sheet */}
        <QuickInputSheet
          open={sheetOpen}
          slotType={sheetSlotType}
          onOpenChange={setSheetOpen}
          onSubmitMock={submitMock}
        />
        <DevAuth />
      </div>
    </TooltipProvider>
  );
}

import { createBrowserClient } from '@supabase/ssr'

export function createClient() {
    return createBrowserClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
    )
}

