import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/client"; // Wait, this is client-side. Need server client?
// Use @supabase/ssr createServerClient for API routes
import { createServerClient, type CookieOptions } from "@supabase/ssr";
import { cookies } from "next/headers";
import { buildAgenda } from "@/lib/smart-agenda/engine";

export async function GET(request: NextRequest) {
    const cookieStore = await cookies();

    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        {
            cookies: {
                getAll() {
                    return cookieStore.getAll()
                },
                setAll(cookiesToSet) {
                    try {
                        cookiesToSet.forEach(({ name, value, options }) =>
                            cookieStore.set(name, value, options)
                        )
                    } catch {
                        // The `setAll` method was called from a Server Component.
                        // This can be ignored if you have middleware refreshing
                        // user sessions.
                    }
                },
            },
        }
    );

    const { data: { user }, error: authError } = await supabase.auth.getUser();

    if (authError || !user) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Param date (default today)
    const today = new Date().toISOString().split('T')[0];
    const dateParam = request.nextUrl.searchParams.get("date") || today;

    // Target User (Support Coach View)
    // If ?user_id=... is present, we try to fetch for that user.
    // RLS will enforce strict access (Coach policy).
    const targetUserId = request.nextUrl.searchParams.get("user_id") || user.id;

    // Fetch events for this user and this day
    const { data: events, error } = await supabase
        .from("events")
        .select("*")
        .eq("user_id", targetUserId) // Explicitly filter by target
        .gte("created_at", `${dateParam}T00:00:00+00:00`)
        .lt("created_at", `${dateParam}T23:59:59+00:00`)
        .order("created_at", { ascending: true });

    if (error) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }

    // Fetch Annotations
    // V0 Strategy: Fetch all for this day?
    // scope_ref should start with YYYY-MM-DD if scope is slot?
    // Or we fetch all for client and filter in engine? 
    // To keep it simple and efficient: 
    // We want all annotations where scope_ref starts with dateParam OR scope_ref IS dateParam (day scope).
    // range search on text is okay for small V0.
    const { data: annotations } = await supabase
        .from("coach_annotations")
        .select("*")
        .eq("client_id", targetUserId)
        .like("scope_ref", `${dateParam}%`); // Covers "2024-01-01" and "2024-01-01_wake"

    // Build Engine
    const agendaProps = buildAgenda(events || [], {
        timezone: "Europe/Paris", // Fixed for V0
        referenceDate: dateParam,
        annotations: annotations || []
    });

    return NextResponse.json(agendaProps);
}

