"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { createClient } from "@/lib/supabase/client";
import { Badge } from "@/components/ui/badge";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";

type ClientSummary = {
    client_id: string;
    last_active: string; // ISO or "Jamais"
    status: "stable" | "sous_tension" | "derive";
};

export default function CoachDashboard() {
    const [clients, setClients] = useState<ClientSummary[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchClients = async () => {
            const supabase = createClient();
            const { data: assignments, error } = await supabase.from("coach_client").select("client_id");

            if (assignments) {
                const summaries: ClientSummary[] = [];

                // N+1 Fetch for V0 (Acceptable for prototype)
                for (const assignment of assignments) {
                    const { data: events } = await supabase
                        .from("events")
                        .select("created_at")
                        .eq("user_id", assignment.client_id)
                        .order("created_at", { ascending: false })
                        .limit(1);

                    const lastEvent = events?.[0];
                    let status: ClientSummary["status"] = "stable";
                    let lastActive = "Jamais";

                    if (lastEvent) {
                        lastActive = new Date(lastEvent.created_at).toLocaleDateString();
                        const diffDays = (new Date().getTime() - new Date(lastEvent.created_at).getTime()) / (1000 * 3600 * 24);
                        if (diffDays > 3) status = "derive";
                        else if (diffDays > 1) status = "sous_tension";
                    } else {
                        status = "derive"; // No data
                    }

                    summaries.push({
                        client_id: assignment.client_id,
                        last_active: lastActive,
                        status
                    });
                }
                setClients(summaries);
            }
            setLoading(false);
        };

        fetchClients();
    }, []);

    if (loading) return <div className="p-8">Chargement...</div>;

    return (
        <div className="p-8 max-w-4xl mx-auto">
            <h1 className="text-2xl font-bold mb-6">Tableau de bord Coach</h1>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {clients.length === 0 ? (
                    <div className="text-muted-foreground col-span-3">Aucun client assigné.</div>
                ) : (
                    clients.map((c) => (
                        <Link key={c.client_id} href={`/coach/${c.client_id}`}>
                            <Card className="hover:bg-muted/50 transition-colors cursor-pointer border-l-4" style={{
                                borderLeftColor: c.status === 'stable' ? '#10b981' : c.status === 'sous_tension' ? '#f59e0b' : '#ef4444'
                            }}>
                                <CardHeader className="pb-2">
                                    <CardTitle className="text-sm font-mono">{c.client_id.slice(0, 8)}...</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <div className="flex justify-between items-center text-sm">
                                        <span className="text-muted-foreground">Actif: {c.last_active}</span>
                                        <Badge variant={c.status === 'stable' ? "secondary" : c.status === 'sous_tension' ? "outline" : "destructive"}>
                                            {c.status === 'stable' ? 'Stable' : c.status === 'sous_tension' ? 'Tension' : 'Dérive'}
                                        </Badge>
                                    </div>
                                </CardContent>
                            </Card>
                        </Link>
                    ))
                )}
            </div>
        </div>
    );
}

