"use client";

import * as React from "react";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription } from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Slider } from "@/components/ui/slider";
import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";
import { Separator } from "@/components/ui/separator";
import { createClient } from "@/lib/supabase/client";
import type { SlotType } from "@/lib/types";

type Props = {
  open: boolean;
  slotType: SlotType | null;
  onOpenChange: (open: boolean) => void;
  onSubmitMock: (payload: Record<string, unknown>) => void;
};

function titleFor(slotType: SlotType): string {
  switch (slotType) {
    case "wake":
      return "Réveil";
    case "meal":
      return "Repas";
    case "water":
      return "Hydratation";
    case "activity":
      return "Activité";
    case "day_close":
      return "Fin de journée";
  }
}

export function QuickInputSheet({ open, slotType, onOpenChange, onSubmitMock }: Props) {
  const [note, setNote] = React.useState("");
  const [s1, setS1] = React.useState<number[]>([3]);
  const [s2, setS2] = React.useState<number[]>([3]);
  const [mealType, setMealType] = React.useState<string>("lunch");

  React.useEffect(() => {
    if (!open) {
      setNote("");
      setS1([3]);
      setS2([3]);
      setMealType("lunch");
    }
  }, [open]);

  const st = slotType ?? "meal";

  // V0 mock: on simule juste un submit, sans backend.
  async function submit() {
    const payload = {
      slot_type: st,
      score_1_5_a: st === "water" ? undefined : s1[0],
      score_1_5_b: st === "water" ? undefined : s2[0],
      meal_type: st === "meal" ? mealType : undefined,
      water_ml: st === "water" ? (note === "250ml" ? 250 : (note === "500ml" ? 500 : 0)) : undefined,
      notes: note,
    };

    onSubmitMock(payload);

    // Supabase Insert
    try {
      const supabase = createClient();
      const {
        data: { user },
      } = await supabase.auth.getUser();

      if (user) {
        const { error } = await supabase.from("events").insert({
          user_id: user.id,
          event_type: `v0.agenda.${st}`,
          payload,
        });
        if (error) console.error("Supabase insert error:", error);
        else console.log("Supabase insert success");
      } else {
        console.warn("No user logged in, skipping Supabase insert");
      }
    } catch (e) {
      console.error("Supabase client error:", e);
    }

    onOpenChange(false);
  }

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="bottom" className="h-[92vh]">
        <SheetHeader>
          <SheetTitle>{titleFor(st)}</SheetTitle>
          <SheetDescription>Input rapide (V0 mock). Max 5 champs. Validation = event.</SheetDescription>
        </SheetHeader>

        <div className="mt-4 space-y-4">
          {st === "meal" ? (
            <div className="space-y-2">
              <div className="text-sm font-medium">Type de repas</div>
              <ToggleGroup type="single" value={mealType} onValueChange={(v) => v && setMealType(v)}>
                <ToggleGroupItem value="breakfast">Petit-déj</ToggleGroupItem>
                <ToggleGroupItem value="lunch">Déjeuner</ToggleGroupItem>
                <ToggleGroupItem value="dinner">Dîner</ToggleGroupItem>
                <ToggleGroupItem value="snack">Snack</ToggleGroupItem>
              </ToggleGroup>
            </div>
          ) : null}

          {st === "water" ? (
            <div className="space-y-4">
              <div className="text-sm font-medium">Ajout rapide</div>
              <div className="flex gap-4">
                <Button variant="outline" className="flex-1" onClick={() => { setNote("250ml"); submit(); }}>
                  + 250ml
                </Button>
                <Button variant="outline" className="flex-1" onClick={() => { setNote("500ml"); submit(); }}>
                  + 500ml
                </Button>
              </div>
              <Separator />
            </div>
          ) : null}

          {st !== "water" && (
            <div className="space-y-2">
              <div className="flex items-center justify-between text-sm">
                <div className="font-medium">Score A</div>
                <div className="text-muted-foreground">{s1[0]}/5</div>
              </div>
              <Slider value={s1} min={1} max={5} step={1} onValueChange={setS1} />
            </div>
          )}

          {st !== "water" && (
            <div className="space-y-2">
              <div className="flex items-center justify-between text-sm">
                <div className="font-medium">Score B</div>
                <div className="text-muted-foreground">{s2[0]}/5</div>
              </div>
              <Slider value={s2} min={1} max={5} step={1} onValueChange={setS2} />
            </div>
          )}

          <Separator />

          <div className="space-y-2">
            <div className="text-sm font-medium">Note courte</div>
            <Textarea value={note} onChange={(e) => setNote(e.target.value)} placeholder="Optionnel (max court)" />
          </div>

          <div className="pt-2">
            <Button className="w-full" onClick={submit}>
              Valider
            </Button>
          </div>
        </div>
      </SheetContent>
    </Sheet>
  );
}

