"use client";

import * as React from "react";
import { useParams } from "next/navigation";
import { AgendaSlotCard } from "@/components/agenda/agenda-slot-card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { ClientAgendaUIProps } from "@/lib/types";

export default function CoachClientAgenda() {
    const params = useParams();
    const clientId = params.clientId as string;
    const [agenda, setAgenda] = React.useState<ClientAgendaUIProps | null>(null);
    const [loading, setLoading] = React.useState(true);

    React.useEffect(() => {
        async function load() {
            // Call API with user_id param
            // TODO: Add date picker support. Defaulting to today.
            const res = await fetch(`/api/agenda?user_id=${clientId}`);
            if (res.ok) {
                setAgenda(await res.json());
            }
            setLoading(false);
        }
        load();
    }, [clientId]);

    // Refresh function logic (simple re-fetch)
    const refresh = async () => {
        setLoading(true);
        const res = await fetch(`/api/agenda?user_id=${clientId}`);
        if (res.ok) setAgenda(await res.json());
        setLoading(false);
    };

    if (loading) return <div>Chargement...</div>;
    if (!agenda) return <div>Erreur ou Accès refusé</div>;

    return (
        <div className="max-w-xl mx-auto min-h-dvh flex flex-col p-4 bg-background">
            <div className="mb-6">
                <div className="text-sm text-muted-foreground mb-1">Vue Coach (Lecture Seule)</div>
                <h1 className="text-xl font-bold font-mono text-xs">{clientId}</h1>
                <Badge variant="secondary" className="mt-2">{agenda.date}</Badge>
            </div>

            <ScrollArea className="flex-1">
                <div className="space-y-3 pb-12">
                    {agenda.agenda_slots.map((slot) => (
                        <AgendaSlotCard
                            key={slot.slot_id}
                            slot={slot}
                            onOpen={() => { }} // Read-only: no interaction for V0 phase 6
                            isCoachView={true}
                            clientId={clientId}
                            onRefresh={refresh}
                        />
                    ))}
                </div>
            </ScrollArea>
        </div>
    );
}

