#!/usr/bin/env node

/**
 * STRYV LAB - Database Migration Script
 * Applies SQL migrations to Supabase database
 */

const fs = require('fs');
const path = require('path');
const { createClient } = require('@supabase/supabase-js');
require('dotenv').config({ path: path.join(__dirname, '../.env.local') });

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL;
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
  console.error('❌ Missing Supabase credentials!');
  console.error('Please set NEXT_PUBLIC_SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY in .env.local');
  process.exit(1);
}

// Create Supabase client with service role (bypasses RLS)
const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
  auth: {
    autoRefreshToken: false,
    persistSession: false
  }
});

async function runMigration(migrationPath) {
  const migrationName = path.basename(migrationPath);
  console.log(`\n📄 Running migration: ${migrationName}`);

  try {
    const sql = fs.readFileSync(migrationPath, 'utf8');

    // Note: Supabase JS client doesn't support raw SQL execution
    // This would require direct Postgres connection or Supabase Management API
    // For now, we'll provide instructions

    console.log('⚠️  This script requires manual execution via Supabase Dashboard or psql');
    console.log('📋 Copy the following SQL to Supabase SQL Editor:\n');
    console.log('─'.repeat(80));
    console.log(sql.substring(0, 500) + '...');
    console.log('─'.repeat(80));

    return false; // Manual step required
  } catch (error) {
    console.error(`❌ Error reading migration: ${error.message}`);
    return false;
  }
}

async function checkSchemaVersion() {
  console.log('🔍 Checking current schema version...');

  try {
    const { data, error } = await supabase
      .from('schema_versions')
      .select('version, applied_at')
      .order('applied_at', { ascending: false })
      .limit(1);

    if (error) {
      if (error.code === '42P01') {
        // Table doesn't exist
        console.log('ℹ️  Schema versions table not found. This is a fresh database.');
        return null;
      }
      throw error;
    }

    if (data && data.length > 0) {
      console.log(`✅ Current schema version: ${data[0].version}`);
      console.log(`   Applied at: ${new Date(data[0].applied_at).toLocaleString()}`);
      return data[0].version;
    }

    return null;
  } catch (error) {
    console.error(`❌ Error checking schema: ${error.message}`);
    return null;
  }
}

async function main() {
  console.log('🚀 STRYV LAB - Database Migration Tool\n');

  // Check current version
  const currentVersion = await checkSchemaVersion();

  // List migrations
  const migrationsDir = path.join(__dirname, '../../supabase/migrations');

  if (!fs.existsSync(migrationsDir)) {
    console.error(`❌ Migrations directory not found: ${migrationsDir}`);
    process.exit(1);
  }

  const migrationFiles = fs.readdirSync(migrationsDir)
    .filter(f => f.endsWith('.sql'))
    .sort();

  console.log(`\n📦 Found ${migrationFiles.length} migration(s):\n`);
  migrationFiles.forEach((file, i) => {
    console.log(`  ${i + 1}. ${file}`);
  });

  console.log('\n━'.repeat(80));
  console.log('📖 MANUAL APPLICATION REQUIRED');
  console.log('━'.repeat(80));
  console.log('\nTo apply these migrations:');
  console.log('\n1. Go to: https://supabase.com/dashboard/project/_/sql/new');
  console.log('2. Copy the content of each migration file');
  console.log('3. Paste and execute in order (001, 002, etc.)');
  console.log('4. Verify with: SELECT * FROM schema_versions;\n');

  console.log('📂 Migration files location:');
  console.log(`   ${migrationsDir}\n`);

  console.log('💡 Alternative: Use Supabase CLI');
  console.log('   $ supabase db push\n');

  // Test connection
  console.log('🔗 Testing Supabase connection...');
  const { data, error } = await supabase.from('schema_versions').select('count', { count: 'exact', head: true });

  if (error && error.code !== '42P01') {
    console.error(`❌ Connection failed: ${error.message}`);
  } else {
    console.log('✅ Connection successful!\n');
  }
}

main().catch(console.error);

