const { createClient } = require('@supabase/supabase-js');
const path = require('path');
require('dotenv').config({ path: path.join(__dirname, '../.env.local') });

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL;
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
  console.error('❌ Missing Supabase credentials!');
  process.exit(1);
}

const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
  auth: {
    autoRefreshToken: false,
    persistSession: false
  }
});

const TEST_USERS = {
  client: {
    email: 'client@stryvlab.test',
    password: 'TestClient123!',
    role: 'client',
    display_name: 'Client de Test'
  },
  coach: {
    email: 'coach@stryvlab.test',
    password: 'TestCoach123!',
    role: 'coach',
    display_name: 'Coach de Test'
  }
};

async function createTestUser(userData) {
  console.log(`\n👤 Creating user: ${userData.email}`);

  try {
    // Check if user exists
    const { data: existingUsers } = await supabase.auth.admin.listUsers();
    const exists = existingUsers?.users?.find(u => u.email === userData.email);

    if (exists) {
      console.log('   ℹ️  User already exists');
      return exists;
    }

    // Create user
    const { data, error } = await supabase.auth.admin.createUser({
      email: userData.email,
      password: userData.password,
      email_confirm: true,
      user_metadata: {
        display_name: userData.display_name,
        role: userData.role
      }
    });

    if (error) throw error;

    console.log('   ✅ User created successfully');
    console.log(`   🆔 User ID: ${data.user.id}`);

    // Update profile role
    const { error: profileError } = await supabase
      .from('user_profiles')
      .update({
        role: userData.role,
        display_name: userData.display_name
      })
      .eq('id', data.user.id);

    if (profileError) {
      console.log(`   ⚠️  Profile update: ${profileError.message}`);
    } else {
      console.log('   ✅ Profile updated');
    }

    return data.user;

  } catch (error) {
    console.error(`   ❌ Error: ${error.message}`);
    return null;
  }
}

